        <!-- Сердце с трещиной, перевязанное лентой/пластырем -->\\n              <g fill=\\\"none\\\" stroke=\\\"#5A4530\\\" stroke-width=\\\"1.1\\\" stroke-linecap=\\\"round\\\" stroke-linejoin=\\\"round\\\">\\n                <!-- Сердце -->\\n                <path d=\\\"M 24 38 Q 10 28, 10 18 Q 10 12, 16 12 Q 21 12, 24 17 Q 27 12, 32 12 Q 38 12, 38 18 Q 38 28, 24 38 Z\\\"\\n                      fill=\\\"#F2C8C8\\\" opacity=\\\"0.45\\\" stroke-width=\\\"1.3\\\"/>\\n                <!-- Трещина зигзагом -->\\n                <path d=\\\"M 24 14 L 22 19 L 26 23 L 23 28 L 26 33 L 24 36\\\"\\n                      stroke=\\\"#5A4530\\\" stroke-width=\\\"1.3\\\" fill=\\\"none\\\"/>\\n                <!-- Пластырь крест-накрест поверх трещины -->\\n                <rect x=\\\"18\\\" y=\\\"22\\\" width=\\\"14\\\" height=\\\"5\\\" rx=\\\"0.5\\\" fill=\\\"#FBF6EB\\\" opacity=\\\"0.85\\\" stroke-width=\\\"1.0\\\"\\n                      transform=\\\"rotate(20 25 24.5)\\\"/>\\n                <!-- Точки на пластыре (отверстия) -->\\n                <circle cx=\\\"20\\\" cy=\\\"23.5\\\" r=\\\"0.4\\\" fill=\\\"#5A4530\\\" stroke=\\\"none\\\"/>\\n                <circle cx=\\\"28\\\" cy=\\\"26\\\" r=\\\"0.4\\\" fill=\\\"#5A4530\\\" stroke=\\\"none\\\"/>\\n                <circle cx=\\\"22\\\" cy=\\\"22\\\" r=\\\"0.4\\\" fill=\\\"#5A4530\\\" stroke=\\\"none\\\"/>\\n                <circle cx=\\\"30\\\" cy=\\\"24.5\\\" r=\\\"0.4\\\" fill=\\\"#5A4530\\\" stroke=\\\"none\\\"/>\\n              </g>\\n            </svg>\\n          </div>\\n          <div class=\\\"barrier-text\\\">\\n            <div class=\\\"barrier-label\\\">Страх обжечься</div>\\n            <div class=\\\"barrier-sub\\\">Однажды уже было больно</div>\\n          </div>\\n          <div class=\\\"check-mark\\\"></div>\\n        </div>\\n\\n        <div class=\\\"barrier-card\\\" data-value=\\\"ex_partner\\\" data-pulse=\\\"3\\\">\\n          <div class=\\\"sketch-icon\\\">\\n            <svg viewBox=\\\"0 0 48 48\\\" xmlns=\\\"http://www.w3.org/2000/svg\\\" aria-hidden=\\\"true\\\">\\n              <!-- Силуэт человека и тень/призрак позади него -->\\n              <g fill=\\\"none\\\" stroke=\\\"#5A4530\\\" stroke-width=\\\"1.1\\\" stroke-linecap=\\\"round\\\" stroke-linejoin=\\\"round\\\">\\n                <!-- Тень-призрак (полупрозрачная) сзади -->\\n                <ellipse cx=\\\"30\\\" cy=\\\"14\\\" rx=\\\"6\\\" ry=\\\"7\\\" fill=\\\"#9D8260\\\" opacity=\\\"0.35\\\" stroke=\\\"#8A7E6F\\\" stroke-width=\\\"0.7\\\" stroke-dasharray=\\\"1.5,1.5\\\"/>\\n                <path d=\\\"M 30 21 Q 22 22, 22 32 L 22 40 L 38 40 L 38 32 Q 38 22, 30 21 Z\\\"\\n                      fill=\\\"#9D8260\\\" opacity=\\\"0.3\\\" stroke=\\\"#8A7E6F\\\" stroke-width=\\\"0.7\\\" stroke-dasharray=\\\"1.5,1.5\\\"/>\\n                <!-- Передняя фигура -->\\n                <ellipse cx=\\\"20\\\" cy=\\\"16\\\" rx=\\\"6.5\\\" ry=\\\"7.5\\\" fill=\\\"#F2E9D2\\\" opacity=\\\"0.7\\\" stroke-width=\\\"1.2\\\"/>\\n                <path d=\\\"M 20 23 Q 11 24, 11 34 L 11 42 L 29 42 L 29 34 Q 29 24, 20 23 Z\\\"\\n                      fill=\\\"#F2E9D2\\\" opacity=\\\"0.7\\\" stroke-width=\\\"1.2\\\"/>\\n                <!-- Голова повёрнута слегка к призраку -->\\n                <ellipse cx=\\\"22.5\\\" cy=\\\"14\\\" rx=\\\"1\\\" ry=\\\"1.3\\\" fill=\\\"#2A2622\\\" stroke=\\\"none\\\"/>\\n              </g>\\n            </svg>\\n          </div>\\n          <div class=\\\"barrier-text\\\">\\n            <div class=\\\"barrier-label\\\">Бывший партнёр</div>\\n            <div class=\\\"barrier-sub\\\">Прошлое держит крепче, чем&nbsp;кажется</div>\\n          </div>\\n          <div class=\\\"check-mark\\\"></div>\\n        </div>\\n\\n        <div class=\\\"barrier-card\\\" data-value=\\\"busy\\\" data-pulse=\\\"4\\\">\\n          <div class=\\\"sketch-icon\\\">\\n            <svg viewBox=\\\"0 0 48 48\\\" xmlns=\\\"http://www.w3.org/2000/svg\\\" aria-hidden=\\\"true\\\">\\n              <!-- Песочные часы с убывающим песком -->\\n              <g fill=\\\"none\\\" stroke=\\\"#5A4530\\\" stroke-width=\\\"1.1\\\" stroke-linecap=\\\"round\\\" stroke-linejoin=\\\"round\\\">\\n                <!-- Каркас часов -->\\n                <line x1=\\\"14\\\" y1=\\\"8\\\" x2=\\\"34\\\" y2=\\\"8\\\" stroke-width=\\\"1.4\\\"/>\\n                <line x1=\\\"14\\\" y1=\\\"40\\\" x2=\\\"34\\\" y2=\\\"40\\\" stroke-width=\\\"1.4\\\"/>\\n                <!-- Верхняя колба -->\\n                <path d=\\\"M 16 8 L 16 14 L 24 24 L 32 14 L 32 8\\\" stroke-width=\\\"1.2\\\"/>\\n                <!-- Нижняя колба -->\\n                <path d=\\\"M 16 40 L 16 34 L 24 24 L 32 34 L 32 40\\\" stroke-width=\\\"1.2\\\"/>\\n                <!-- Песок в верхней колбе (немного) -->\\n                <path d=\\\"M 18 8 L 18 12 L 24 20 L 30 12 L 30 8 Z\\\" fill=\\\"#C9A36B\\\" opacity=\\\"0.6\\\"/>\\n                <!-- Тонкая струйка песка -->\\n                <line x1=\\\"24\\\" y1=\\\"22\\\" x2=\\\"24\\\" y2=\\\"28\\\" stroke=\\\"#C9A36B\\\" stroke-width=\\\"0.9\\\" opacity=\\\"0.8\\\"/>\\n                <!-- Песок в нижней (много) -->\\n                <path d=\\\"M 17 40 L 17 35 Q 17 32, 24 30 Q 31 32, 31 35 L 31 40 Z\\\" fill=\\\"#C9A36B\\\" opacity=\\\"0.65\\\"/>\\n                <!-- Часовые стрелки маленькие сбоку (намёк на время) -->\\n                <line x1=\\\"42\\\" y1=\\\"12\\\" x2=\\\"42\\\" y2=\\\"16\\\" stroke-width=\\\"0.7\\\" opacity=\\\"0.55\\\"/>\\n                <line x1=\\\"42\\\" y1=\\\"14\\\" x2=\\\"44\\\" y2=\\\"14\\\" stroke-width=\\\"0.7\\\" opacity=\\\"0.55\\\"/>\\n              </g>\\n            </svg>\\n          </div>\\n          <div class=\\\"barrier-text\\\">\\n            <div class=\\\"barrier-label\\\">Постоянная занятость</div>\\n            <div class=\\\"barrier-sub\\\">Времени всё&nbsp;меньше</div>\\n          </div>\\n          <div class=\\\"check-mark\\\"></div>\\n        </div>\\n\\n        <div class=\\\"barrier-card\\\" data-value=\\\"not_attractive\\\" data-pulse=\\\"5\\\">\\n          <div class=\\\"sketch-icon\\\">\\n            <svg viewBox=\\\"0 0 48 48\\\" xmlns=\\\"http://www.w3.org/2000/svg\\\" aria-hidden=\\\"true\\\">\\n              <!-- Зеркало в раме, фигура отвернулась -->\\n              <g fill=\\\"none\\\" stroke=\\\"#5A4530\\\" stroke-width=\\\"1.1\\\" stroke-linecap=\\\"round\\\" stroke-linejoin=\\\"round\\\">\\n                <!-- Зеркало -->\\n                <ellipse cx=\\\"32\\\" cy=\\\"20\\\" rx=\\\"9\\\" ry=\\\"13\\\" fill=\\\"#FBF6EB\\\" opacity=\\\"0.7\\\" stroke-width=\\\"1.3\\\"/>\\n                <!-- Рамка золотая -->\\n                <ellipse cx=\\\"32\\\" cy=\\\"20\\\" rx=\\\"10\\\" ry=\\\"14\\\" fill=\\\"none\\\" stroke=\\\"#C9A36B\\\" stroke-width=\\\"1.0\\\" opacity=\\\"0.7\\\"/>\\n                <!-- Блик в зеркале -->\\n                <path d=\\\"M 28 14 Q 30 13, 32 15\\\" stroke=\\\"#FBF6EB\\\" stroke-width=\\\"1.5\\\" opacity=\\\"0.85\\\"/>\\n                <!-- Ножка зеркала -->\\n                <line x1=\\\"32\\\" y1=\\\"34\\\" x2=\\\"32\\\" y2=\\\"42\\\" stroke-width=\\\"1.2\\\"/>\\n                <line x1=\\\"28\\\" y1=\\\"42\\\" x2=\\\"36\\\" y2=\\\"42\\\" stroke-width=\\\"1.2\\\"/>\\n                <!-- Силуэт фигуры, отвернувшейся от зеркала (только спина и голова) -->\\n                <ellipse cx=\\\"14\\\" cy=\\\"14\\\" rx=\\\"4\\\" ry=\\\"5\\\" fill=\\\"#F2E9D2\\\" opacity=\\\"0.7\\\" stroke-width=\\\"1.1\\\"/>\\n                <path d=\\\"M 14 19 Q 8 20, 8 30 L 8 38 L 19 38 L 19 30 Q 19 20, 14 19 Z\\\"\\n                      fill=\\\"#F2E9D2\\\" opacity=\\\"0.7\\\" stroke-width=\\\"1.1\\\"/>\\n                <!-- Стрелка движения (отвернулась) -->\\n                <path d=\\\"M 17 24 L 13 24\\\" stroke-width=\\\"0.8\\\" opacity=\\\"0.55\\\"/>\\n                <path d=\\\"M 14 22 L 12 24 L 14 26\\\" stroke-width=\\\"0.8\\\" opacity=\\\"0.55\\\"/>\\n              </g>\\n            </svg>\\n          </div>\\n          <div class=\\\"barrier-text\\\">\\n            <div class=\\\"barrier-label\\\">Я никому не&nbsp;нравлюсь</div>\\n            <div class=\\\"barrier-sub\\\">Сомневаюсь в&nbsp;себе</div>\\n          </div>\\n          <div class=\\\"check-mark\\\"></div>\\n        </div>\\n\\n        <div class=\\\"barrier-card\\\" data-value=\\\"no_one_attractive\\\" data-pulse=\\\"6\\\">\\n          <div class=\\\"sketch-icon\\\">\\n            <svg viewBox=\\\"0 0 48 48\\\" xmlns=\\\"http://www.w3.org/2000/svg\\\" aria-hidden=\\\"true\\\">\\n              <!-- Окно с открытыми ставнями и пустота -->\\n              <g fill=\\\"none\\\" stroke=\\\"#5A4530\\\" stroke-width=\\\"1.1\\\" stroke-linecap=\\\"round\\\" stroke-linejoin=\\\"round\\\">\\n                <!-- Рама окна -->\\n                <rect x=\\\"10\\\" y=\\\"8\\\" width=\\\"28\\\" height=\\\"32\\\" fill=\\\"#FBF6EB\\\" opacity=\\\"0.45\\\" stroke-width=\\\"1.3\\\"/>\\n                <!-- Две створки -->\\n                <line x1=\\\"24\\\" y1=\\\"8\\\" x2=\\\"24\\\" y2=\\\"40\\\" stroke-width=\\\"1.2\\\"/>\\n                <line x1=\\\"10\\\" y1=\\\"24\\\" x2=\\\"38\\\" y2=\\\"24\\\" stroke-width=\\\"1.2\\\"/>\\n                <!-- Через окно — пустой пейзаж (горизонт) -->\\n                <line x1=\\\"10\\\" y1=\\\"28\\\" x2=\\\"22\\\" y2=\\\"28\\\" stroke-width=\\\"0.7\\\" opacity=\\\"0.55\\\"/>\\n                <line x1=\\\"26\\\" y1=\\\"28\\\" x2=\\\"38\\\" y2=\\\"28\\\" stroke-width=\\\"0.7\\\" opacity=\\\"0.55\\\"/>\\n                <!-- Маленькое одинокое облако -->\\n                <path d=\\\"M 14 14 Q 13 12, 15 12 Q 16 11, 17 12 Q 19 11, 20 13 Q 21 14, 19 14 L 15 14 Z\\\"\\n                      fill=\\\"#FBF6EB\\\" opacity=\\\"0.7\\\" stroke-width=\\\"0.7\\\"/>\\n                <!-- Подоконник -->\\n                <line x1=\\\"8\\\" y1=\\\"40\\\" x2=\\\"40\\\" y2=\\\"40\\\" stroke-width=\\\"1.3\\\"/>\\n                <line x1=\\\"6\\\" y1=\\\"42\\\" x2=\\\"42\\\" y2=\\\"42\\\" stroke-width=\\\"1.0\\\" opacity=\\\"0.65\\\"/>\\n              </g>\\n            </svg>\\n          </div>\\n          <div class=\\\"barrier-text\\\">\\n            <div class=\\\"barrier-label\\\">Мне никто не&nbsp;нравится</div>\\n            <div class=\\\"barrier-sub\\\">Не нахожу того&nbsp;самого</div>\\n          </div>\\n          <div class=\\\"check-mark\\\"></div>\\n        </div>\\n      </div>\\n    </div>\\n\\n  </div>\\n\\n</div>\\n\\n<div class=\\\"next-toast\\\" id=\\\"toast\\\">Переход к экрану 11 → следующий вопрос</div>\\n\\n<script>\\n  let partnerGender = 'female';\\n  let partnerEthnicity = 'european';\\n  let dreamLocation = 'ocean';\\n  try {\\n    const data = JSON.parse(sessionStorage.getItem('lovia_data') || '{}');\\n    if (data.partner_gender) partnerGender = data.partner_gender;\\n    if (data.partner_ethnicity) partnerEthnicity = data.partner_ethnicity;\\n    if (data.dream_location) dreamLocation = data.dream_location;\\n  } catch(e) {}\\n  document.body.classList.add('partner-' + partnerGender);\\n  document.body.setAttribute('data-ethnicity', partnerEthnicity);\\n  document.body.setAttribute('data-location', dreamLocation);\\n\\n  let transitioning = false;\\n\\n  function selectBarrier(card, value) {\\n    if (transitioning) return;\\n    transitioning = true;\\n\\n    document.querySelectorAll('.barrier-card').forEach(c => c.classList.remove('selected'));\\n    card.classList.add('selected');\\n\\n    try {\\n      const data = JSON.parse(sessionStorage.getItem('lovia_data') || '{}');\\n      data.dating_barrier = value;\\n      sessionStorage.setItem('lovia_data', JSON.stringify(data));\\n    } catch(e) {}\\n\\n    setTimeout(() => {\\n      document.body.classList.add('choice-made');\\n      document.body.classList.add('eyes-drawn');\\n    }, 400);\\n\\n    setTimeout(() => {\\n      document.body.classList.add('exiting');\\n      const toast = document.getElementById('toast');\\n      setTimeout(() => {\\n        if (window.parent && window.parent !== window) { try { window.parent.postMessage({type:'lovia:next'}, '*'); } catch(e){} }\\n\\n        toast.classList.add('show');\\n        setTimeout(() => toast.classList.remove('show'), 2200);\\n      }, 600);\\n    }, 2500);\\n  }\\n\\n  document.addEventListener('DOMContentLoaded', function() {\\n    document.querySelectorAll('.barrier-card').forEach(function(card) {\\n      let touched = false;\\n\\n      card.addEventListener('touchend', function(e) {\\n        touched = true;\\n        const value = card.getAttribute('data-value');\\n        selectBarrier(card, value);\\n        e.preventDefault();\\n        setTimeout(() => { touched = false; }, 500);\\n      }, { passive: false });\\n\\n      card.addEventListener('click', function(e) {\\n        if (touched) { e.preventDefault(); return; }\\n        const value = card.getAttribute('data-value');\\n        selectBarrier(card, value);\\n      });\\n    });\\n  });\\n<\\\\/script>\\n\\n\\n<!-- ========== LOVIA PNG PORTRAIT OVERLAY ========== -->\\n<style>\\n  .canvas-area .portrait-sketch,\\n  .canvas-area .jawline-existing,\\n  .canvas-area .shoulders-existing,\\n  .canvas-area .ethnicity-existing,\\n  .canvas-area .mouth-existing,\\n  .canvas-area g[class*=\\\"-existing\\\"],\\n  .canvas-area g[class*=\\\"sketch-\\\"] {\\n    display: none !important;\\n  }\\n  .lovia-png-portrait {\\n    position: absolute;\\n    left: 11.05%;\\n    top: 12.96%;\\n    width: 77.89%;\\n    height: 64.81%;\\n    pointer-events: none;\\n    z-index: 5;\\n    display: flex;\\n    align-items: center;\\n    justify-content: center;\\n  }\\n  .lovia-png-portrait img.lovia-png-img {\\n    max-width: 100%;\\n    max-height: 100%;\\n    width: auto;\\n    height: auto;\\n    object-fit: contain;\\n    display: block;\\n    transition: opacity 0.5s ease;\\n  }\\n<\\\\/style>\\n<script>\\n(function() {\\n  window.LOVIA_PORTRAIT_FRAME = 5;\\n  // URL-\\u044b \\u043f\\u043e\\u0441\\u0442\\u0440\\u043e\\u0435\\u043d\\u044b \\u043f\\u043e \\u0448\\u0430\\u0431\\u043b\\u043e\\u043d\\u0443: w%20-step_NN.png (\\u0436\\u0435\\u043d\\u0449\\u0438\\u043d\\u0430) \\u0438 m%20-step_NN.png (\\u043c\\u0443\\u0436\\u0447\\u0438\\u043d\\u0430)\\n  // %20 \\u2014 \\u044d\\u0442\\u043e URL-encoding \\u043f\\u0440\\u043e\\u0431\\u0435\\u043b\\u0430\\n  var BASE = \\\"https://raw.githubusercontent.com/TeCaK315/malbert1/main\\\";\\n  var FRAME_PAD = \\\"05\\\";\\n  \\n  function readPartnerGender() {\\n    try {\\n      var data = JSON.parse(sessionStorage.getItem(\\\"lovia_data\\\") || \\\"{}\\\");\\n      return data.partner_gender === \\\"male\\\" ? \\\"male\\\" : \\\"female\\\";\\n    } catch(e) { return \\\"female\\\"; }\\n  }\\n  \\n  function buildUrl(gender, framePad) {\\n    var prefix = gender === \\\"male\\\" ? \\\"m\\\" : \\\"w\\\";\\n    return BASE + \\\"/\\\" + prefix + \\\"%20-step_\\\" + framePad + \\\".png\\\";\\n  }\\n  \\n  function applyPortrait() {\\n    var easelWrapper = document.querySelector(\\\".easel-wrapper\\\");\\n    if (!easelWrapper) return;\\n    \\n    var container = easelWrapper.querySelector(\\\".lovia-png-portrait\\\");\\n    if (!container) {\\n      container = document.createElement(\\\"div\\\");\\n      container.className = \\\"lovia-png-portrait\\\";\\n      easelWrapper.appendChild(container);\\n    }\\n    \\n    var img = container.querySelector(\\\".lovia-png-img\\\");\\n    if (!img) {\\n      img = document.createElement(\\\"img\\\");\\n      img.className = \\\"lovia-png-img\\\";\\n      img.alt = \\\"\\\";\\n      img.loading = \\\"eager\\\";\\n      container.appendChild(img);\\n    }\\n    \\n    var gender = readPartnerGender();\\n    var url = buildUrl(gender, FRAME_PAD);\\n    \\n    if (img.src !== url) {\\n      img.src = url;\\n    }\\n  }\\n  \\n  if (document.readyState === \\\"loading\\\") {\\n    document.addEventListener(\\\"DOMContentLoaded\\\", applyPortrait);\\n  } else {\\n    applyPortrait();\\n  }\\n  setTimeout(applyPortrait, 100);\\n  setTimeout(applyPortrait, 500);\\n  setTimeout(applyPortrait, 1500);\\n})();\\n<\\\\/script></body>\\n</html>\\n\"}, {\"id\": 11, \"label\": \"Дата рождения\", \"html\": \"<!DOCTYPE html>\\n<html lang=\\\"ru\\\">\\n<head>\\n<meta charset=\\\"UTF-8\\\" />\\n<meta name=\\\"viewport\\\" content=\\\"width=device-width, initial-scale=1.0, maximum-scale=1.0, user-scalable=no\\\" />\\n<title>Lovia — Шаг 10 из 22</title>\\n\\n<link rel=\\\"preconnect\\\" href=\\\"https://fonts.googleapis.com\\\">\\n<link rel=\\\"preconnect\\\" href=\\\"https://fonts.gstatic.com\\\" crossorigin>\\n<link href=\\\"https://fonts.googleapis.com/css2?family=Cormorant+Garamond:ital,wght@0,300;0,400;0,500;1,300;1,400&family=Inter+Tight:wght@300;400;500;600&display=swap\\\" rel=\\\"stylesheet\\\">\\n\\n<style>\\n  :root {\\n    --bg:        #F4EDE2;\\n    --bg-deep:   #EDE3D2;\\n    --bg-paper:  #F9F2E3;\\n    --ink:       #2A2622;\\n    --ink-soft:  #5C534A;\\n    --muted:     #8A7E6F;\\n    --gold:      #B8956A;\\n    --gold-deep: #8E6D44;\\n    --gold-light:#D4B58A;\\n    --pencil:    #4A3A2A;\\n  }\\n\\n  * { box-sizing: border-box; margin: 0; padding: 0; -webkit-tap-highlight-color: transparent; }\\n\\n  html, body {\\n    width: 100%;\\n    min-height: 100%;\\n    background: var(--bg);\\n    color: var(--ink);\\n    font-family: 'Inter Tight', system-ui, sans-serif;\\n    font-weight: 400;\\n    -webkit-font-smoothing: antialiased;\\n    text-rendering: optimizeLegibility;\\n    overflow-x: hidden;\\n  }\\n\\n  body::before {\\n    content: '';\\n    position: fixed; inset: 0;\\n    background:\\n      radial-gradient(ellipse at 20% 10%, rgba(255,255,255,0.5) 0%, transparent 50%),\\n      radial-gradient(ellipse at 80% 90%, rgba(184,149,106,0.10) 0%, transparent 60%),\\n      linear-gradient(180deg, var(--bg) 0%, var(--bg-deep) 100%);\\n    pointer-events: none;\\n    z-index: 0;\\n  }\\n  body::after {\\n    content: '';\\n    position: fixed; inset: 0;\\n    background-image: url(\\\"data:image/svg+xml;utf8,<svg xmlns='http://www.w3.org/2000/svg' width='200' height='200'><filter id='n'><feTurbulence type='fractalNoise' baseFrequency='0.85' numOctaves='2' stitchTiles='stitch'/><feColorMatrix values='0 0 0 0 0.15  0 0 0 0 0.12  0 0 0 0 0.10  0 0 0 0.18 0'/></filter><rect width='100%' height='100%' filter='url(%23n)' opacity='0.5'/></svg>\\\");\\n    opacity: 0.55;\\n    mix-blend-mode: multiply;\\n    pointer-events: none;\\n    z-index: 1;\\n  }\\n\\n  /* ===== ФОН ЛОКАЦИИ ===== */\\n  .location-bg {\\n    position: fixed;\\n    inset: 0;\\n    z-index: 1;\\n    pointer-events: none;\\n    opacity: 0;\\n    animation: locationFadeIn 1.5s 0.3s ease-out forwards;\\n  }\\n  @keyframes locationFadeIn { to { opacity: 1; } }\\n\\n  .location-gradient {\\n    position: absolute;\\n    inset: 0;\\n    transition: background 0.8s ease;\\n  }\\n  body[data-location=\\\"ocean\\\"] .location-gradient {\\n    background: linear-gradient(180deg, rgba(168, 197, 212, 0.45) 0%, rgba(190, 200, 200, 0.25) 50%, rgba(232, 215, 184, 0.35) 100%);\\n  }\\n  body[data-location=\\\"forest\\\"] .location-gradient {\\n    background: linear-gradient(180deg, rgba(216, 220, 184, 0.45) 0%, rgba(190, 185, 150, 0.25) 50%, rgba(200, 184, 154, 0.35) 100%);\\n  }\\n  body[data-location=\\\"ski\\\"] .location-gradient {\\n    background: linear-gradient(180deg, rgba(200, 208, 220, 0.45) 0%, rgba(220, 222, 220, 0.25) 50%, rgba(232, 226, 213, 0.35) 100%);\\n  }\\n  body[data-location=\\\"home\\\"] .location-gradient {\\n    background: linear-gradient(180deg, rgba(232, 208, 181, 0.45) 0%, rgba(220, 180, 145, 0.30) 50%, rgba(208, 172, 140, 0.40) 100%);\\n  }\\n\\n  .location-accent { position: absolute; inset: 0; width: 100%; height: 100%; }\\n  .location-accent svg { width: 100%; height: 100%; display: block; }\\n  .location-accent .accent { display: none; }\\n  body[data-location=\\\"ocean\\\"]  .location-accent .accent.ocean,\\n  body[data-location=\\\"forest\\\"] .location-accent .accent.forest,\\n  body[data-location=\\\"ski\\\"]    .location-accent .accent.ski,\\n  body[data-location=\\\"home\\\"]   .location-accent .accent.home { display: block; }\\n  .location-accent path {\\n    fill: none;\\n    stroke-linecap: round;\\n    stroke-linejoin: round;\\n    opacity: 0.22;\\n  }\\n\\n  .stage {\\n    position: relative;\\n    z-index: 2;\\n    width: 100%;\\n    min-height: 100vh;\\n    min-height: 100svh;\\n    display: flex;\\n    flex-direction: column;\\n    align-items: center;\\n    justify-content: flex-start;\\n    padding: 6px 12px 12px;\\n  }\\n\\n  .top-bar {\\n    display: flex;\\n    flex-direction: column;\\n    align-items: center;\\n    flex-shrink: 0;\\n    margin-bottom: 4px;\\n    opacity: 0;\\n    animation: fadeUp 0.9s 0.1s ease-out forwards;\\n  }\\n  .topmark {\\n    font-size: 9px;\\n    letter-spacing: 0.4em;\\n    color: var(--muted);\\n    text-transform: uppercase;\\n    margin-bottom: 1px;\\n  }\\n  .brand {\\n    display: flex;\\n    align-items: center;\\n    gap: 7px;\\n    margin-bottom: 6px;\\n  }\\n  .brand-mark {\\n    width: 12px; height: 12px;\\n    border: 1px solid var(--gold);\\n    border-radius: 50%;\\n    position: relative;\\n  }\\n  .brand-mark::after {\\n    content: '';\\n    position: absolute; inset: 3px;\\n    background: var(--gold);\\n    border-radius: 50%;\\n  }\\n  .brand-name {\\n    font-family: 'Cormorant Garamond', serif;\\n    font-weight: 400;\\n    font-size: 16px;\\n    letter-spacing: 0.32em;\\n    color: var(--ink);\\n    text-transform: uppercase;\\n    padding-left: 2px;\\n  }\\n\\n  .progress-bar {\\n    width: 160px;\\n    max-width: 50vw;\\n    height: 2px;\\n    background: rgba(184, 149, 106, 0.18);\\n    border-radius: 1px;\\n    overflow: hidden;\\n    position: relative;\\n  }\\n  .progress-bar-fill {\\n    position: absolute;\\n    left: 0; top: 0; bottom: 0;\\n    width: 45.5%;\\n    background: linear-gradient(90deg, var(--gold), var(--gold-deep));\\n    border-radius: 1px;\\n    box-shadow: 0 0 4px rgba(184, 149, 106, 0.5);\\n    animation: progressGrow 1s 0.6s ease-out forwards;\\n    transform-origin: left center;\\n    transform: scaleX(0);\\n  }\\n  @keyframes progressGrow { from { transform: scaleX(0); } to { transform: scaleX(1); } }\\n\\n  /* ===== МОЛЬБЕРТ ===== */\\n  .easel-wrapper {\\n    position: relative;\\n    width: 100%;\\n    max-width: 280px;\\n    aspect-ratio: 380 / 540;\\n    flex-shrink: 0;\\n    opacity: 0;\\n    animation: easelAppear 1.2s 0.4s ease-out forwards;\\n    z-index: 3;\\n    margin-bottom: 14px;\\n  }\\n  @keyframes easelAppear {\\n    from { opacity: 0; transform: translateY(15px) scale(0.97); }\\n    to   { opacity: 1; transform: translateY(0) scale(1); }\\n  }\\n\\n  .easel-svg { position: absolute; inset: 0; width: 100%; height: 100%; display: block; }\\n\\n  .canvas-area {\\n    transform-origin: center;\\n    animation: canvasBreathe 7s 2.5s ease-in-out infinite;\\n  }\\n  @keyframes canvasBreathe { 0%,100% { transform: scale(1); } 50% { transform: scale(1.005); } }\\n\\n  .palette-shine { opacity: 0; animation: shineFade 3.5s 3.5s ease-in-out infinite; }\\n  @keyframes shineFade { 0%,100% { opacity: 0; } 50% { opacity: 0.6; } }\\n\\n  /* ===== ПОРТРЕТ ===== */\\n  .portrait-sketch,\\n  .jawline-existing,\\n  .shoulders-existing,\\n  .ethnicity-existing,\\n  .mouth-existing,\\n  .eyes-existing,\\n  .nose-existing { opacity: 0; }\\n  .portrait-sketch path,\\n  .jawline-existing path,\\n  .shoulders-existing path,\\n  .ethnicity-existing path,\\n  .mouth-existing path,\\n  .eyes-existing path,\\n  .nose-existing path {\\n    fill: none;\\n    stroke: var(--pencil);\\n    stroke-linecap: round;\\n    stroke-linejoin: round;\\n  }\\n  body.partner-female .portrait-sketch.female,\\n  body.partner-female .jawline-existing.female,\\n  body.partner-female .shoulders-existing.female,\\n  body.partner-female .mouth-existing.female,\\n  body.partner-female .eyes-existing.female,\\n  body.partner-female .nose-existing.female,\\n  body.partner-male   .portrait-sketch.male,\\n  body.partner-male   .jawline-existing.male,\\n  body.partner-male   .shoulders-existing.male,\\n  body.partner-male   .mouth-existing.male,\\n  body.partner-male   .eyes-existing.male,\\n  body.partner-male   .nose-existing.male,\\n  body[data-ethnicity=\\\"european\\\"] .ethnicity-existing.european,\\n  body[data-ethnicity=\\\"latin\\\"]    .ethnicity-existing.latin,\\n  body[data-ethnicity=\\\"african\\\"]  .ethnicity-existing.african,\\n  body[data-ethnicity=\\\"asian\\\"]    .ethnicity-existing.asian,\\n  body[data-ethnicity=\\\"any\\\"]      .ethnicity-existing.any {\\n    opacity: 0.78;\\n  }\\n\\n  /* ===== НОВАЯ ДЕТАЛЬ: ВОЛОСЫ ===== */\\n  .hair-new { opacity: 0; transition: opacity 0.5s ease; }\\n  .hair-new path {\\n    fill: none;\\n    stroke: var(--pencil);\\n    stroke-linecap: round;\\n    stroke-linejoin: round;\\n    stroke-dasharray: var(--len, 100);\\n    stroke-dashoffset: var(--len, 100);\\n  }\\n  body.hair-drawn.partner-female .hair-new.female,\\n  body.hair-drawn.partner-male   .hair-new.male { opacity: 0.85; }\\n  body.hair-drawn.partner-female .hair-new.female path,\\n  body.hair-drawn.partner-male   .hair-new.male path {\\n    animation: drawSketch 1.2s ease-out forwards;\\n    animation-delay: var(--delay, 0s);\\n  }\\n  @keyframes drawSketch { to { stroke-dashoffset: 0; } }\\n\\n  /* ===== КАРТОЧКА-БЛОКНОТ ===== */\\n  .question-card {\\n    position: relative;\\n    width: 100%;\\n    max-width: 420px;\\n    background: var(--bg-paper);\\n    border-radius: 6px;\\n    padding: 16px 16px 18px;\\n    box-shadow: 0 6px 22px rgba(42, 38, 34, 0.10), 0 1px 3px rgba(42, 38, 34, 0.08);\\n    opacity: 0;\\n    animation: cardAppear 1s 0.8s ease-out forwards;\\n    z-index: 3;\\n    transition: opacity 0.5s ease, transform 0.5s ease;\\n  }\\n  @keyframes cardAppear { from { opacity: 0; transform: translateY(15px); } to { opacity: 1; transform: translateY(0); } }\\n  .question-card::before {\\n    content: '';\\n    position: absolute;\\n    inset: 0;\\n    border-radius: 6px;\\n    background-image: url(\\\"data:image/svg+xml;utf8,<svg xmlns='http://www.w3.org/2000/svg' width='100' height='100'><filter id='n2'><feTurbulence type='fractalNoise' baseFrequency='1.2' numOctaves='1' stitchTiles='stitch'/><feColorMatrix values='0 0 0 0 0.18  0 0 0 0 0.14  0 0 0 0 0.10  0 0 0 0.08 0'/></filter><rect width='100%' height='100%' filter='url(%23n2)'/></svg>\\\");\\n    opacity: 0.6;\\n    pointer-events: none;\\n    mix-blend-mode: multiply;\\n  }\\n  .question-card > .corner {\\n    position: absolute;\\n    width: 12px; height: 12px;\\n    border-color: var(--gold);\\n    border-style: solid;\\n    border-width: 0;\\n    pointer-events: none;\\n  }\\n  .question-card > .corner.tl { top: 6px; left: 6px; border-top-width: 1.2px; border-left-width: 1.2px; }\\n  .question-card > .corner.tr { top: 6px; right: 6px; border-top-width: 1.2px; border-right-width: 1.2px; }\\n  .question-card > .corner.bl { bottom: 6px; left: 6px; border-bottom-width: 1.2px; border-left-width: 1.2px; }\\n  .question-card > .corner.br { bottom: 6px; right: 6px; border-bottom-width: 1.2px; border-right-width: 1.2px; }\\n\\n  body.choice-made .question-card {\\n    opacity: 0.25;\\n    transform: translateY(8px);\\n    pointer-events: none;\\n  }\\n\\n  .question-heading {\\n    font-family: 'Cormorant Garamond', serif;\\n    font-weight: 300;\\n    font-size: 22px;\\n    line-height: 1.2;\\n    color: var(--ink);\\n    letter-spacing: -0.005em;\\n    margin: 0 0 8px;\\n    text-align: center;\\n    position: relative;\\n    z-index: 1;\\n  }\\n\\n  .question-hint {\\n    font-family: 'Inter Tight', sans-serif;\\n    font-weight: 400;\\n    font-size: 12px;\\n    line-height: 1.4;\\n    color: var(--ink-soft);\\n    text-align: center;\\n    margin: 0 0 16px;\\n    padding: 0 8px;\\n    position: relative;\\n    z-index: 1;\\n    font-style: italic;\\n  }\\n\\n  /* ===== ДАТА-ПИКЕР (СКРОЛЛ-КОЛЁСА) ===== */\\n  .date-picker {\\n    position: relative;\\n    z-index: 1;\\n    display: flex;\\n    align-items: center;\\n    justify-content: center;\\n    gap: 8px;\\n    padding: 10px 4px;\\n    margin-bottom: 16px;\\n    background: rgba(255, 250, 240, 0.5);\\n    border-radius: 6px;\\n    border: 1px solid rgba(184, 149, 106, 0.25);\\n  }\\n\\n  .date-wheel {\\n    flex: 1;\\n    position: relative;\\n    height: 140px;\\n    overflow: hidden;\\n    cursor: grab;\\n  }\\n  .date-wheel:active { cursor: grabbing; }\\n\\n  /* Выделение центральной позиции — золотая линия сверху и снизу */\\n  .date-wheel::before,\\n  .date-wheel::after {\\n    content: '';\\n    position: absolute;\\n    left: 4px; right: 4px;\\n    height: 1px;\\n    background: linear-gradient(90deg, transparent, var(--gold), transparent);\\n    z-index: 2;\\n    pointer-events: none;\\n  }\\n  .date-wheel::before { top: calc(50% - 18px); }\\n  .date-wheel::after { top: calc(50% + 18px); }\\n\\n  /* Градиенты затухания сверху и снизу */\\n  .date-wheel-fade {\\n    position: absolute;\\n    inset: 0;\\n    pointer-events: none;\\n    z-index: 3;\\n    background:\\n      linear-gradient(180deg, var(--bg-paper) 0%, transparent 25%, transparent 75%, var(--bg-paper) 100%);\\n    background-color: transparent;\\n  }\\n\\n  .date-wheel-list {\\n    position: absolute;\\n    left: 0; right: 0;\\n    top: 50%;\\n    will-change: transform;\\n    transition: transform 0.3s cubic-bezier(0.2, 0.8, 0.2, 1);\\n    touch-action: pan-y;\\n  }\\n\\n  .date-wheel-item {\\n    height: 36px;\\n    display: flex;\\n    align-items: center;\\n    justify-content: center;\\n    font-family: 'Cormorant Garamond', serif;\\n    font-size: 18px;\\n    font-weight: 400;\\n    color: var(--muted);\\n    line-height: 1;\\n    transition: color 0.3s ease, font-size 0.3s ease, font-weight 0.3s ease;\\n    user-select: none;\\n    -webkit-user-select: none;\\n  }\\n  .date-wheel-item.selected {\\n    color: var(--ink);\\n    font-size: 22px;\\n    font-weight: 500;\\n  }\\n  .date-wheel-item.neighbor {\\n    color: var(--ink-soft);\\n    font-size: 19px;\\n  }\\n\\n  /* Подписи под колёсами */\\n  .date-labels {\\n    display: flex;\\n    justify-content: center;\\n    gap: 8px;\\n    margin-top: -10px;\\n    margin-bottom: 16px;\\n    position: relative;\\n    z-index: 1;\\n  }\\n  .date-label {\\n    flex: 1;\\n    text-align: center;\\n    font-family: 'Inter Tight', sans-serif;\\n    font-size: 10px;\\n    font-weight: 500;\\n    letter-spacing: 0.25em;\\n    text-transform: uppercase;\\n    color: var(--muted);\\n  }\\n\\n  /* ===== КНОПКА \\\"ПРОДОЛЖИТЬ\\\" ===== */\\n  .btn-wrap {\\n    display: flex;\\n    justify-content: center;\\n    position: relative;\\n    z-index: 1;\\n  }\\n  .btn-continue {\\n    position: relative;\\n    display: inline-block;\\n    padding: 12px 36px;\\n    background: var(--ink);\\n    color: var(--bg);\\n    border: none;\\n    font-family: 'Inter Tight', sans-serif;\\n    font-size: 12px;\\n    font-weight: 500;\\n    letter-spacing: 0.28em;\\n    text-transform: uppercase;\\n    cursor: pointer;\\n    overflow: hidden;\\n    transition: transform 0.4s cubic-bezier(0.2, 0.8, 0.2, 1), background 0.4s ease;\\n    box-shadow: 0 4px 14px rgba(42, 38, 34, 0.22);\\n    touch-action: manipulation;\\n    -webkit-tap-highlight-color: rgba(184, 149, 106, 0.15);\\n    -webkit-appearance: none;\\n    -webkit-user-select: none;\\n    user-select: none;\\n  }\\n  .btn-continue::before {\\n    content: '';\\n    position: absolute;\\n    top: 0; left: -100%;\\n    width: 100%; height: 100%;\\n    background: linear-gradient(90deg, transparent, rgba(184,149,106,0.5), transparent);\\n    transition: left 0.7s ease;\\n  }\\n  .btn-continue:hover::before { left: 100%; }\\n  .btn-continue:hover { background: var(--gold-deep); transform: translateY(-2px); }\\n  .btn-continue:active { transform: translateY(0); }\\n\\n  body.exiting .top-bar,\\n  body.exiting .question-card {\\n    opacity: 0 !important;\\n    transition: opacity 0.5s ease;\\n    pointer-events: none;\\n  }\\n  body.exiting .easel-wrapper {\\n    transform: scale(0.95);\\n    opacity: 0.6;\\n    transition: all 0.7s ease;\\n  }\\n\\n  @keyframes fadeUp { from { opacity: 0; transform: translateY(12px); } to { opacity: 1; transform: translateY(0); } }\\n\\n  /* АДАПТИВ */\\n  @media (max-width: 380px) {\\n    .easel-wrapper { max-width: 240px; }\\n    .question-heading { font-size: 19px; }\\n    .question-hint { font-size: 11px; margin-bottom: 14px; }\\n    .date-wheel-item { font-size: 16px; }\\n    .date-wheel-item.selected { font-size: 19px; }\\n    .date-wheel-item.neighbor { font-size: 17px; }\\n    .date-wheel { height: 130px; }\\n    .question-card { padding: 14px 12px 16px; }\\n  }\\n  @media (max-width: 340px) {\\n    .easel-wrapper { max-width: 220px; margin-bottom: 10px; }\\n    .question-heading { font-size: 17px; }\\n    .question-hint { font-size: 10.5px; }\\n    .date-picker { gap: 6px; padding: 8px 2px; }\\n    .date-wheel-item { font-size: 15px; }\\n    .date-wheel-item.selected { font-size: 17px; }\\n    .btn-continue { padding: 10px 28px; font-size: 11px; }\\n  }\\n  @media (min-width: 768px) {\\n    .stage { max-width: 1100px; margin: 0 auto; padding: 24px; }\\n    .main-row {\\n      display: flex;\\n      flex-direction: row;\\n      gap: 40px;\\n      align-items: center;\\n      width: 100%;\\n      justify-content: center;\\n    }\\n    .easel-wrapper { max-width: 300px; margin-bottom: 0; flex-shrink: 0; }\\n    .question-card { max-width: 560px; padding: 32px 32px 32px; flex-shrink: 1; flex-grow: 1; }\\n    .question-heading { font-size: 28px; margin-bottom: 10px; }\\n    .question-hint { font-size: 14px; margin-bottom: 24px; }\\n    .date-wheel-item { font-size: 20px; }\\n    .date-wheel-item.selected { font-size: 24px; }\\n    .date-wheel-item.neighbor { font-size: 21px; }\\n    .date-wheel { height: 160px; }\\n    .date-label { font-size: 11px; }\\n    .btn-continue { padding: 14px 44px; font-size: 13px; }\\n  }\\n  @media (min-width: 1024px) {\\n    .easel-wrapper { max-width: 340px; }\\n    .question-card { max-width: 620px; padding: 36px; }\\n    .question-heading { font-size: 30px; }\\n    .question-hint { font-size: 15px; }\\n  }\\n\\n  .next-toast {\\n    position: fixed;\\n    bottom: 24px;\\n    left: 50%;\\n    transform: translateX(-50%);\\n    background: var(--ink);\\n    color: var(--bg);\\n    padding: 12px 22px;\\n    font-size: 12px;\\n    letter-spacing: 0.15em;\\n    text-transform: uppercase;\\n    border-radius: 4px;\\n    opacity: 0;\\n    pointer-events: none;\\n    transition: opacity 0.5s ease;\\n    z-index: 10;\\n  }\\n  .next-toast.show { opacity: 1; }\\n<\/style>\\n</head>\\n<body>\\n\\n<div class=\\\"location-bg\\\">\\n  <div class=\\\"location-gradient\\\"></div>\\n  <div class=\\\"location-accent\\\">\\n    <svg viewBox=\\\"0 0 400 800\\\" preserveAspectRatio=\\\"xMidYMid slice\\\" xmlns=\\\"http://www.w3.org/2000/svg\\\">\\n      <g class=\\\"accent ocean\\\">\\n        <path d=\\\"M 0 420 Q 50 412, 100 420 T 200 420 T 300 420 T 400 420\\\" stroke=\\\"#4A6878\\\" stroke-width=\\\"1.4\\\"/>\\n        <path d=\\\"M 0 445 Q 60 438, 120 445 T 240 445 T 360 445 T 400 445\\\" stroke=\\\"#4A6878\\\" stroke-width=\\\"1.1\\\" opacity=\\\"0.6\\\"/>\\n      </g>\\n      <g class=\\\"accent forest\\\">\\n        <path d=\\\"M 55 720 L 90 660 L 125 720 Z\\\" stroke=\\\"#4A6038\\\" stroke-width=\\\"1.2\\\"/>\\n        <path d=\\\"M 60 670 L 90 600 L 120 670 Z\\\" stroke=\\\"#4A6038\\\" stroke-width=\\\"1.2\\\"/>\\n        <path d=\\\"M 65 620 L 90 540 L 115 620 Z\\\" stroke=\\\"#4A6038\\\" stroke-width=\\\"1.2\\\"/>\\n        <path d=\\\"M 70 570 L 90 480 L 110 570 Z\\\" stroke=\\\"#4A6038\\\" stroke-width=\\\"1.2\\\"/>\\n        <path d=\\\"M 85 720 L 85 740 M 95 720 L 95 740\\\" stroke=\\\"#4A6038\\\" stroke-width=\\\"1.2\\\"/>\\n      </g>\\n      <g class=\\\"accent ski\\\">\\n        <path d=\\\"M 0 480 L 60 360 L 130 440 L 210 320 L 290 410 L 360 350 L 400 390\\\" stroke=\\\"#5A6878\\\" stroke-width=\\\"1.4\\\"/>\\n        <path d=\\\"M 0 440 L 80 380 L 160 430 L 240 360 L 320 420 L 400 380\\\" stroke=\\\"#5A6878\\\" stroke-width=\\\"0.9\\\" opacity=\\\"0.6\\\"/>\\n      </g>\\n      <g class=\\\"accent home\\\">\\n        <path d=\\\"M 100 750 L 100 600 Q 100 540, 200 540 Q 300 540, 300 600 L 300 750\\\" stroke=\\\"#7A4A30\\\" stroke-width=\\\"1.5\\\"/>\\n        <path d=\\\"M 140 750 L 140 620 Q 140 580, 200 580 Q 260 580, 260 620 L 260 750\\\" stroke=\\\"#7A4A30\\\" stroke-width=\\\"1.0\\\" opacity=\\\"0.6\\\"/>\\n        <path d=\\\"M 170 700 Q 178 660, 185 690 Q 195 650, 200 685 Q 208 655, 215 690 Q 222 660, 230 700\\\" stroke=\\\"#7A4A30\\\" stroke-width=\\\"1.1\\\" opacity=\\\"0.7\\\"/>\\n      </g>\\n    </svg>\\n  </div>\\n</div>\\n\\n<div class=\\\"stage\\\">\\n\\n  <div class=\\\"top-bar\\\">\\n    <div class=\\\"topmark\\\">— Atelier de l'Âme —</div>\\n    <div class=\\\"brand\\\">\\n      <span class=\\\"brand-mark\\\"></span>\\n      <span class=\\\"brand-name\\\">Lovia</span>\\n    </div>\\n    <div class=\\\"progress-bar\\\">\\n      <div class=\\\"progress-bar-fill\\\"></div>\\n    </div>\\n  </div>\\n\\n  <div class=\\\"main-row\\\">\\n\\n    <div class=\\\"easel-wrapper\\\">\\n      <svg class=\\\"easel-svg\\\" viewBox=\\\"0 0 380 540\\\" xmlns=\\\"http://www.w3.org/2000/svg\\\" aria-hidden=\\\"true\\\" preserveAspectRatio=\\\"xMidYMid meet\\\">\\n\\n        <defs>\\n          <linearGradient id=\\\"woodMain\\\" x1=\\\"0%\\\" y1=\\\"0%\\\" x2=\\\"100%\\\" y2=\\\"0%\\\">\\n            <stop offset=\\\"0%\\\" stop-color=\\\"#5A3F26\\\"/>\\n            <stop offset=\\\"25%\\\" stop-color=\\\"#8B6843\\\"/>\\n            <stop offset=\\\"50%\\\" stop-color=\\\"#A37F5A\\\"/>\\n            <stop offset=\\\"75%\\\" stop-color=\\\"#7D5938\\\"/>\\n            <stop offset=\\\"100%\\\" stop-color=\\\"#4A2F1A\\\"/>\\n          </linearGradient>\\n          <linearGradient id=\\\"woodSide\\\" x1=\\\"0%\\\" y1=\\\"0%\\\" x2=\\\"100%\\\" y2=\\\"0%\\\">\\n            <stop offset=\\\"0%\\\" stop-color=\\\"#6B4A2E\\\"/>\\n            <stop offset=\\\"50%\\\" stop-color=\\\"#8B6843\\\"/>\\n            <stop offset=\\\"100%\\\" stop-color=\\\"#3F2918\\\"/>\\n          </linearGradient>\\n          <radialGradient id=\\\"canvasRealistic\\\" cx=\\\"50%\\\" cy=\\\"45%\\\" r=\\\"65%\\\">\\n            <stop offset=\\\"0%\\\" stop-color=\\\"#FBF6EB\\\"/>\\n            <stop offset=\\\"60%\\\" stop-color=\\\"#F2E9D2\\\"/>\\n            <stop offset=\\\"100%\\\" stop-color=\\\"#D4C49E\\\"/>\\n          </radialGradient>\\n          <pattern id=\\\"canvasWeave\\\" x=\\\"0\\\" y=\\\"0\\\" width=\\\"4\\\" height=\\\"4\\\" patternUnits=\\\"userSpaceOnUse\\\">\\n            <rect width=\\\"4\\\" height=\\\"4\\\" fill=\\\"#F8F0DA\\\"/>\\n            <line x1=\\\"0\\\" y1=\\\"1\\\" x2=\\\"4\\\" y2=\\\"1\\\" stroke=\\\"#E5D5B0\\\" stroke-width=\\\"0.5\\\" opacity=\\\"0.6\\\"/>\\n            <line x1=\\\"0\\\" y1=\\\"3\\\" x2=\\\"4\\\" y2=\\\"3\\\" stroke=\\\"#D9C698\\\" stroke-width=\\\"0.4\\\" opacity=\\\"0.5\\\"/>\\n            <line x1=\\\"1\\\" y1=\\\"0\\\" x2=\\\"1\\\" y2=\\\"4\\\" stroke=\\\"#E5D5B0\\\" stroke-width=\\\"0.4\\\" opacity=\\\"0.4\\\"/>\\n            <line x1=\\\"3\\\" y1=\\\"0\\\" x2=\\\"3\\\" y2=\\\"4\\\" stroke=\\\"#D9C698\\\" stroke-width=\\\"0.3\\\" opacity=\\\"0.35\\\"/>\\n            <circle cx=\\\"1\\\" cy=\\\"1\\\" r=\\\"0.4\\\" fill=\\\"#C8B58A\\\" opacity=\\\"0.5\\\"/>\\n            <circle cx=\\\"3\\\" cy=\\\"3\\\" r=\\\"0.4\\\" fill=\\\"#C8B58A\\\" opacity=\\\"0.5\\\"/>\\n          </pattern>\\n          <pattern id=\\\"woodGrain\\\" x=\\\"0\\\" y=\\\"0\\\" width=\\\"60\\\" height=\\\"6\\\" patternUnits=\\\"userSpaceOnUse\\\">\\n            <rect width=\\\"60\\\" height=\\\"6\\\" fill=\\\"transparent\\\"/>\\n            <path d=\\\"M 0 3 Q 15 1, 30 3 T 60 3\\\" stroke=\\\"#3A2615\\\" stroke-width=\\\"0.4\\\" fill=\\\"none\\\" opacity=\\\"0.5\\\"/>\\n            <path d=\\\"M 0 4.5 Q 20 5.5, 40 4 T 60 4.5\\\" stroke=\\\"#5A3F26\\\" stroke-width=\\\"0.3\\\" fill=\\\"none\\\" opacity=\\\"0.4\\\"/>\\n          </pattern>\\n          <filter id=\\\"dropShadow\\\" x=\\\"-30%\\\" y=\\\"-30%\\\" width=\\\"160%\\\" height=\\\"160%\\\">\\n            <feGaussianBlur in=\\\"SourceAlpha\\\" stdDeviation=\\\"4\\\"/>\\n            <feOffset dx=\\\"2\\\" dy=\\\"6\\\" result=\\\"offsetblur\\\"/>\\n            <feComponentTransfer><feFuncA type=\\\"linear\\\" slope=\\\"0.32\\\"/></feComponentTransfer>\\n            <feMerge><feMergeNode/><feMergeNode in=\\\"SourceGraphic\\\"/></feMerge>\\n          </filter>\\n        </defs>\\n\\n        <ellipse cx=\\\"190\\\" cy=\\\"525\\\" rx=\\\"140\\\" ry=\\\"9\\\" fill=\\\"#000\\\" opacity=\\\"0.15\\\"/>\\n        <g opacity=\\\"0.65\\\">\\n          <path d=\\\"M 185 55 L 195 520 L 205 520 L 195 55 Z\\\" fill=\\\"url(#woodSide)\\\"/>\\n          <rect x=\\\"178\\\" y=\\\"430\\\" width=\\\"35\\\" height=\\\"6\\\" fill=\\\"url(#woodSide)\\\" rx=\\\"1\\\"/>\\n        </g>\\n        <path d=\\\"M 180 50 L 55 520 L 70 520 L 195 50 Z\\\" fill=\\\"url(#woodMain)\\\"/>\\n        <path d=\\\"M 180 50 L 55 520 L 70 520 L 195 50 Z\\\" fill=\\\"url(#woodGrain)\\\" opacity=\\\"0.4\\\"/>\\n        <path d=\\\"M 180 50 L 55 520 L 63 520 L 188 50 Z\\\" fill=\\\"#000\\\" opacity=\\\"0.18\\\"/>\\n        <path d=\\\"M 191 50 L 68 520 L 70 520 L 193 50 Z\\\" fill=\\\"#FFFFFF\\\" opacity=\\\"0.12\\\"/>\\n        <ellipse cx=\\\"120\\\" cy=\\\"280\\\" rx=\\\"3\\\" ry=\\\"1.5\\\" fill=\\\"#3A2615\\\" opacity=\\\"0.6\\\" transform=\\\"rotate(-72 120 280)\\\"/>\\n        <ellipse cx=\\\"90\\\" cy=\\\"410\\\" rx=\\\"2\\\" ry=\\\"1\\\" fill=\\\"#3A2615\\\" opacity=\\\"0.5\\\" transform=\\\"rotate(-72 90 410)\\\"/>\\n        <path d=\\\"M 195 50 L 320 520 L 305 520 L 180 50 Z\\\" fill=\\\"url(#woodMain)\\\"/>\\n        <path d=\\\"M 195 50 L 320 520 L 305 520 L 180 50 Z\\\" fill=\\\"url(#woodGrain)\\\" opacity=\\\"0.4\\\"/>\\n        <path d=\\\"M 195 50 L 320 520 L 312 520 L 187 50 Z\\\" fill=\\\"#000\\\" opacity=\\\"0.18\\\"/>\\n        <path d=\\\"M 184 50 L 307 520 L 305 520 L 182 50 Z\\\" fill=\\\"#FFFFFF\\\" opacity=\\\"0.10\\\"/>\\n        <ellipse cx=\\\"255\\\" cy=\\\"280\\\" rx=\\\"2.5\\\" ry=\\\"1.3\\\" fill=\\\"#3A2615\\\" opacity=\\\"0.55\\\" transform=\\\"rotate(72 255 280)\\\"/>\\n        <ellipse cx=\\\"285\\\" cy=\\\"430\\\" rx=\\\"2\\\" ry=\\\"1\\\" fill=\\\"#3A2615\\\" opacity=\\\"0.5\\\" transform=\\\"rotate(72 285 430)\\\"/>\\n        <circle cx=\\\"190\\\" cy=\\\"50\\\" r=\\\"5\\\" fill=\\\"#3A2615\\\"/>\\n        <circle cx=\\\"190\\\" cy=\\\"50\\\" r=\\\"3.5\\\" fill=\\\"#5A4530\\\"/>\\n        <circle cx=\\\"190\\\" cy=\\\"50\\\" r=\\\"1.8\\\" fill=\\\"#2A1810\\\"/>\\n        <circle cx=\\\"189\\\" cy=\\\"49\\\" r=\\\"0.8\\\" fill=\\\"#FFFFFF\\\" opacity=\\\"0.4\\\"/>\\n        <rect x=\\\"60\\\" y=\\\"425\\\" width=\\\"260\\\" height=\\\"10\\\" fill=\\\"url(#woodMain)\\\" rx=\\\"1\\\"/>\\n        <rect x=\\\"60\\\" y=\\\"425\\\" width=\\\"260\\\" height=\\\"3\\\" fill=\\\"#FFFFFF\\\" opacity=\\\"0.15\\\"/>\\n        <rect x=\\\"60\\\" y=\\\"432\\\" width=\\\"260\\\" height=\\\"3\\\" fill=\\\"#000\\\" opacity=\\\"0.2\\\"/>\\n        <circle cx=\\\"78\\\" cy=\\\"430\\\" r=\\\"2.2\\\" fill=\\\"#2A1810\\\"/>\\n        <circle cx=\\\"78\\\" cy=\\\"430\\\" r=\\\"1\\\" fill=\\\"#5A4530\\\"/>\\n        <circle cx=\\\"302\\\" cy=\\\"430\\\" r=\\\"2.2\\\" fill=\\\"#2A1810\\\"/>\\n        <circle cx=\\\"302\\\" cy=\\\"430\\\" r=\\\"1\\\" fill=\\\"#5A4530\\\"/>\\n\\n        <g class=\\\"canvas-area\\\" filter=\\\"url(#dropShadow)\\\">\\n          <rect x=\\\"47\\\" y=\\\"73\\\" width=\\\"296\\\" height=\\\"350\\\" fill=\\\"#000\\\" opacity=\\\"0.08\\\" rx=\\\"1\\\"/>\\n          <rect x=\\\"42\\\" y=\\\"70\\\" width=\\\"296\\\" height=\\\"350\\\" fill=\\\"url(#canvasRealisti